class Solution(object):
    def findRotation(self, mat, target):
        def rotate_90(matrix):
            n = len(matrix)
            return [[matrix[n-1-j][i] for j in range(n)] for i in range(n)]
        current = [row[:] for row in mat]
        for _ in range(4):
            if current == target:
                return True
            current = rotate_90(current)
        return False
